        for (let i = 0; i < sceneImages.length; i++) {
            const currentSceneImage = sceneImages[i];

            results.push({
                json: {
                    // 继承上游所有其他字段 (如 taskId 等)
                    ...json,

                    // 1. 保持完整的产品图数组
                    base64_cpimage: productImages,

                    // 2. 【关键修改】将当前的单张场景图包装成数组结构
                    // 输出结果示例: "base64_ckimage": [ "data:image/jpeg;base64..." ]
                    base64_ckimage: [currentSceneImage]
                }
            });
        }
    }
}

return results;

// ==========================================
// 【1】获取输入数据并提取原始文本
// ==========================================
const items = $input.all();

const texts = items.map(item => {
    try {
        return item.json.candidates[0].content.parts[0].text;
    } catch (e) {
        return null;
    }
}).filter(Boolean);

// 如果没有有效文本，直接返回空
if (texts.length === 0) {
    return [{ json: { error: "未找到有效的文本内容" } }];
}

// ==========================================
// 【2】定义结构化拆解函数
// ==========================================
function parseTextToSections(text) {
    // 定义大模型输出的5个固定锚点
    const anchors = [
        "(产品核心信息)", 
        "(画面构图场景布局及文案)", 
        "(风格与字体方案)", 
        "(配色方案)", 
        "(Amazon A+ 详情图核心逻辑)"
    ];

    // 找到每个锚点在文本中的确切位置
    const indices = anchors.map(a => text.indexOf(a));

    // 初始化5个部分
    let sections = {
        part_1_core_info: "",
        part_2_image_specs: "",
        part_3_font_style: "",
        part_4_color_scheme: "",
        part_5_core_logic: ""
    };

    // 如果连第一个锚点都找不到，说明格式完全错误
    if (indices[0] === -1) return sections;

    // 按顺序切割文本，并增加边界保护
    sections.part_1_core_info = text.substring(indices[0], indices[1] !== -1 ? indices[1] : undefined).trim();
    if (indices[1] !== -1) {
        sections.part_2_image_specs = text.substring(indices[1], indices[2] !== -1 ? indices[2] : undefined).trim();
    }
    if (indices[2] !== -1) {
        sections.part_3_font_style = text.substring(indices[2], indices[3] !== -1 ? indices[3] : undefined).trim();
    }
    if (indices[3] !== -1) {
        sections.part_4_color_scheme = text.substring(indices[3], indices[4] !== -1 ? indices[4] : undefined).trim();
    }
    if (indices[4] !== -1) {
        sections.part_5_core_logic = text.substring(indices[4]).trim();
    }

    return sections;
}

// ==========================================
// 【3】遍历所有输入项，执行拆解并输出
// ==========================================
const results = texts.map(text => {
    return {
        json: parseTextToSections(text)
    };
});

return results;

// ================================================ 
// 获取 taskId，计算完整路径，按顺序命名图片 
// 统一 binary 键名为 data，重命名 fileName 为 img_1.png 格式 
// 同时创建日期+taskId的文件夹 
// ================================================ 

const fs = require('fs'); 
const path = require('path'); 

const allItems = $input.all(); 

// 尝试多种方式获取 taskId 
let taskId = ''; 

// 方式1：从当前节点的 json 中获取 
const firstItem = allItems[0] || {}; 
if (firstItem.json?.taskId) { 
  taskId = firstItem.json.taskId; 
} 

// 方式2：从"path"节点获取（生成ID的节点） 
if (!taskId) { 
  try { 
    const basePathItems = $('path').all(); 
    if (basePathItems && basePathItems.length > 0) { 
      taskId = basePathItems[0].json?.taskId || ''; 
    } 
  } catch (e) { 
    console.log('无法从 path 获取 taskId'); 
  } 
} 

// 方式3：从 Respond to Webhook2 节点获取 
if (!taskId) { 
  try { 
    const respondItems = $('Respond to Webhook2').all(); 
    if (respondItems && respondItems.length > 0) { 
      taskId = respondItems[0].json?.taskId || ''; 
    } 
  } catch (e) { 
    console.log('无法从 Respond to Webhook2 获取 taskId'); 
  } 
} 

// 如果还是没有，使用时间戳作为备用 
if (!taskId) { 
  console.log('警告: 未找到 taskId，使用时间戳作为备用'); 
  taskId = `task_${Date.now()}`; 
} 

console.log('获取到的 taskId:', taskId); 

// 生成日期文件夹路径 
const now = new Date(); 
const yyyy = String(now.getFullYear()); 
const mm = String(now.getMonth() + 1).padStart(2, '0'); 
const dd = String(now.getDate()).padStart(2, '0'); 

// 文件夹路径 = 基础路径/日期/taskId 
const basePath = '/home/node/.n8n/AI-WEB'; 
const folderPath = path.join(basePath, yyyy, mm, dd, taskId); 

// 创建文件夹（如果不存在） 
let created = false; 
if (!fs.existsSync(folderPath)) { 
  fs.mkdirSync(folderPath, { recursive: true }); 
  created = true; 
  console.log('创建文件夹:', folderPath); 
} 

// 按顺序为每个 item 分配图片编号（img_1, img_2, img_3...） 
return allItems.map((item, index) => { 
  // 修改命名方式：img_1, img_2, img_3... 
  const imageName = `img_${index + 1}`; 
  const fullImagePath = `${folderPath}/${imageName}.png`; 

  // 获取原始 binary 数据 
  const originalBinary = item.binary || {}; 

  // 修改 binary：将所有键名统一为 "data"，fileName 改为 img_X.png 格式 
  const modifiedBinary = {}; 

  // 取第一个 binary 数据的属性作为模板 
  const firstKey = Object.keys(originalBinary)[0]; 
  const templateData = firstKey ? originalBinary[firstKey] : {}; 

  // 获取原始扩展名 
  const extension = (templateData.fileName || 'image.png').split('.').pop() || 'png'; 
  // 新文件名：img_1.png, img_2.png... 
  const newFileName = `${imageName}.${extension}`; 

  // 统一键名为 "data" 
  modifiedBinary['data'] = { 
    ...templateData, 
    fileName: newFileName 
  }; 

  console.log(`生成文件: ${newFileName}`); 

  return { 
    json: { 
      ...item.json, 
      taskId: taskId, 
      basePath: basePath, 
      imageName: imageName, 
      fullImagePath: fullImagePath, 
      // 传递给 Read/Write Files from Disk 
      savePath: fullImagePath, 
      // 用于创建文件夹 
      folderPath: folderPath, 
      created: created, 
      year: yyyy, 
      month: mm, 
      day: dd 
    }, 
    binary: modifiedBinary 
  }; 
});

// ================================================
// n8n Code 节点专用代码
// 功能：将上游所有数据原样传递，并为每个item添加图片数量统计
// 返回：所有输入项，每个项的JSON中都增加了imageCount字段
// ================================================

// 遍历输入的所有 items
for (const item of $input.all()) {
  // 动态计算当前 item 的 binary 中包含多少张图片
  // 如果 item.binary 不存在，则其键的数量为 0
  const calculatedImageCount = item.binary ? Object.keys(item.binary).length : 0;

  // 将计算出的图片数量更新到 item 的 json 部分
  item.json.imageCount = calculatedImageCount;

  // 可选：打印日志信息用于调试
  console.log(`Item ${item.json.image_key || 'unknown'} has ${calculatedImageCount} image(s) in its binary data.`);
}

// 返回所有经过处理的输入项
return $input.all();

// ================================================
// n8n Code 节点专用代码
// 功能1：获取当前节点的输入数据（$input.all()）
// 功能2：动态提取当前输入 binary 中所有的图片
// 功能3：主动获取 Edit Fields 节点的 binary 图像数据（修正逻辑）
// 功能4：提取干净的 JSON 文字信息（适用于 HTTP 请求）
// 返回：合并后的数据，包含输入 JSON + 所有图片 + Edit Fields 的图片 + 干净字符串
// ================================================

const processInputAndImages = () => {
  try {
    // 1. 获取当前节点的输入数据（所有 items，通常是 1 个）
    const inputItems = $input.all();
    const firstInput = inputItems && inputItems.length > 0 ? inputItems[0] : {};
    const inputJson = firstInput.json || {};
    const inputBinary = firstInput.binary || {};

    // 2. 动态提取当前输入 binary 中所有的图片
    const allImages = {};
    let totalImageCount = 0;

    Object.keys(inputBinary).forEach(key => {
      // 不再限制特定前缀，直接提取所有 binary 图片
      if (inputBinary[key]) {
        allImages[key] = { ...inputBinary[key] };  // 深拷贝 binary 对象
        totalImageCount++;
      }
    });

    // 调试日志
    console.log('当前输入 binary 总键数:', Object.keys(inputBinary).length);
    console.log('提取到的图片数:', totalImageCount);
    console.log('图片键名列表:', Object.keys(allImages));

    // 3. 主动获取 Edit Fields 节点的 binary 图像数据（修正逻辑：寻找 cpimage 开头）
    let editFieldsImages = [];
    let editFieldsBinary = {};
    let editFieldsImageCount = 0;
    let editFieldsConnected = false;

    try {
      const editFieldsItems = $('Edit Fields').all();

      if (editFieldsItems && editFieldsItems.length > 0) {
        editFieldsItems.forEach((item, idx) => {
          const itemBinary = item.binary || {};

          Object.keys(itemBinary).forEach(key => {
            // 修正点：将 'ckimage' 改为 'cpimage'
            if (key.startsWith('cpimage') && itemBinary[key]) {
              const img = itemBinary[key];
              editFieldsImages.push({
                fieldName: key,
                fileName: img.fileName || '',
                mimeType: img.mimeType || '',
                fileExtension: img.fileExtension || '',
                fileSize: img.fileSize || '',
                sourceItemIndex: idx
              });

              // 带前缀避免冲突
              editFieldsBinary[`editFields_${key}_${idx}`] = itemBinary[key];
              editFieldsImageCount++;
            }
          });
        });

        if (editFieldsImageCount > 0) {
          editFieldsConnected = true;
          console.log(`成功从 Edit Fields 节点提取 ${editFieldsImageCount} 张图片`);
        }
      }
    } catch (editFieldsErr) {
      console.log('获取 Edit Fields 失败:', editFieldsErr.message);
    }

    // ==========================================
    // 新增功能：提取干净的文字信息 (Clean JSON String)
    // ==========================================
    let cleanJsonString = '';
    try {
      // 核心修复：使用 JSON.stringify 自动转义双引号 " 和换行符 \n
      // 这样生成的字符串可以直接作为 JSON 值使用
      cleanJsonString = JSON.stringify(inputJson);
    } catch (jsonErr) {
      console.log('生成干净字符串失败:', jsonErr.message);
      cleanJsonString = JSON.stringify(inputJson); // 降级处理
    }

    // 4. 合并所有 binary：当前节点的所有图片 + Edit Fields 的 cpimage 图片
    const mergedBinary = {
      ...allImages,              // 所有图片
      ...editFieldsBinary       // editFields_cpimageX_...
    };

    // 5. 返回结果
    return [{
      json: {
        // 输入的原始 JSON 数据
        inputData: inputJson,

        // 当前节点的所有图片元数据
        allImages: allImages,
        totalImageCount: totalImageCount,
        imageKeys: Object.keys(allImages),

        // Edit Fields 的图片元数据（修正后）
        editFieldsImages: editFieldsImages,
        editFieldsImageCount: editFieldsImageCount,
        editFieldsConnected: editFieldsConnected,

        // 总计
        finalTotalImageCount: Object.keys(mergedBinary).length,
        source: 'merged_all_images_and_editFields',

        // --- 新增字段：干净的 JSON 字符串 ---
        cleanJsonString: cleanJsonString
      },

      // 合并后的 binary 数据
      binary: mergedBinary
    }];

  } catch (err) {
    console.log('执行失败:', err.message);
    return [{
      json: {
        error: '执行失败',
        errorDetail: err.message
      }
    }];
  }
};

// 执行并返回
return processInputAndImages();

