// n8n Code 节点专用代码 
// 功能1：提取 Edit Fields 节点中 cpimage 开头的图片
// 功能2：从 Webhook 获取 ProductInformation 并处理成 JSON 格式
// 功能3：收集 base64_cpimage 和 base64_ckimage 数据
// ================================================ 

const processAllData = () => {
  try {
    // ========== 功能1：处理 ProductInformation ==========
    let productInfo = '';

    try {
      // 从 Webhook 获取 ProductInformation
      const webhookItem = $('Webhook').first();
      if (webhookItem && webhookItem.json && webhookItem.json.body) {
        productInfo = webhookItem.json.body['ProductInformation'] || '';
      }
    } catch (webhookErr) {
      console.log('获取 Webhook 数据失败:', webhookErr.message);
    }

    // 处理 ProductInformation：清理特殊字符，使其成为有效的 JSON 字符串
    let processedProductInfo = '';
    if (productInfo) {
      processedProductInfo = productInfo
        .replace(/\\/g, '\\\\')
        .replace(/"/g, '\\"')
        .replace(/\n/g, '\\n')
        .replace(/\r/g, '\\r')
        .replace(/\t/g, '\\t')
        .trim();
    }

    // ========== 功能2：处理 base64_cpimage 和 base64_ckimage ==========
    let base64_cpimage = [];
    let base64_ckimage = [];
    let chatInput = '';

    const items = $input.all();
    for (const item of items) {
      if (item.json && item.json.base64_cpimage && Array.isArray(item.json.base64_cpimage)) {
        base64_cpimage.push(...item.json.base64_cpimage);
      }

      if (item.json && item.json.base64_ckimage && Array.isArray(item.json.base64_ckimage)) {
        base64_ckimage.push(...item.json.base64_ckimage);
      }

      if (item.json && !chatInput && item.json.chatInput) {
        chatInput = item.json.chatInput;
      }
    }

    // ========== 功能3：从 Edit Fields 提取 cpimage 图片 ==========
    let editFieldsData = {};
    let editFieldsBinary = {};
    let extractedImages = {};
    let extractedImageCount = 0;

    try {
      const editFieldsItems = $('Edit Fields').all();

      if (editFieldsItems && editFieldsItems.length > 0) {
        const firstItem = editFieldsItems[0];
        editFieldsData = firstItem.json || {};
        editFieldsBinary = firstItem.binary || {};

        Object.keys(editFieldsBinary).forEach(key => {
          if (key.startsWith('cpimage')) {
            extractedImages[key] = { ...editFieldsBinary[key] };
            extractedImageCount++;
          }
        });
      }
    } catch (editFieldsErr) {
      console.log('获取 Edit Fields 节点失败:', editFieldsErr.message);
    }

    // ========== 输出结果 ==========
    const result = {
      productInfo: processedProductInfo,
      productInfoRaw: productInfo,
      base64_cpimage: base64_cpimage,
      base64_ckimage: base64_ckimage,
      chatInput: chatInput,
      extractedImages: extractedImages,
      extractedImageCount: extractedImageCount,
      extractedImageKeys: Object.keys(extractedImages),
      source: 'processed_data_with_product_info'
    };

    console.log('ProductInformation 长度:', productInfo.length);
    console.log('处理后 ProductInformation:', processedProductInfo.substring(0, 100) + '...');
    console.log('base64_cpimage 数量:', base64_cpimage.length);
    console.log('base64_ckimage 数量:', base64_ckimage.length);
    console.log('提取的 cpimage 图片数:', extractedImageCount);

    return [{
      json: result,
      binary: extractedImages
    }];

  } catch (err) {
    console.log('执行失败:', err.message);
    return [{
      json: {
        error: '执行失败',
        errorDetail: err.message
      }
    }];
