// 同时提取 ckimage 和 cpimage 开头的 binary
// 只有两个前缀都存在图片时，才提取；否则不提取（binary 返回空）

const binary = $input.item.binary || {};

const hasCkimage = Object.keys(binary).some(key => key.startsWith('ckimage'));
const hasCpimage = Object.keys(binary).some(key => key.startsWith('cpimage'));

// 只有两个前缀都存在，才进行提取
if (!hasCkimage || !hasCpimage) {
